$$
\begin{aligned}
\beta_{search_traffic} &\sim \text{Normal}(mu=0,\, sigma=10) \\
\sigma_{search_traffic} &\sim \text{HalfNormal}(sigma=1) \\
\beta_{sales} &\sim \text{Normal}(mu=0,\, sigma=10) \\
\sigma_{sales} &\sim \text{HalfNormal}(sigma=1)
\\[6pt]
\mu_{search_traffic} &= \beta_{0,\,search_traffic} + a \cdot \mathrm{brand_spend} + \mathrm{season} \\
\mathrm{search_traffic} &\sim \text{Normal}(\mu_{search_traffic},\, \sigma_{search_traffic}) \\
\mu_{sales} &= \beta_{0,\,sales} \\
&\quad + b \cdot \mathrm{search_traffic} \\
&\quad + c \cdot \mathrm{brand_spend} \\
&\quad + d \cdot \mathrm{perf_spend} \\
&\quad + \mathrm{season} \\
\mathrm{sales} &\sim \text{Normal}(\mu_{sales},\, \sigma_{sales}) \\
indirect &\equiv a \cdot b
\end{aligned}
$$
:::
